using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    #region CalculateTotal – DataRow tests

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 10, 0.20, 0.00, DisplayName = "Zero unit price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    [DataRow(100.00, 2, 1.0, 400.00, DisplayName = "Maximum tax rate (100%)")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price throws")]
    public void CalculateTotal_NegativeUnitPrice_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity throws")]
    public void CalculateTotal_NegativeQuantity_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, 1, -0.01, DisplayName = "Tax rate below 0 throws")]
    [DataRow(10.00, 1, 1.01, DisplayName = "Tax rate above 1 throws")]
    public void CalculateTotal_InvalidTaxRate_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    #endregion

    #region ApplyDiscount – DynamicData tests

    public static IEnumerable<object[]> DiscountTestCases
    {
        get
        {
            yield return new object[] { 100.00m, 0m, 100.00m };   // No discount
            yield return new object[] { 100.00m, 10m, 90.00m };   // 10% off
            yield return new object[] { 100.00m, 50m, 50.00m };   // Half off
            yield return new object[] { 100.00m, 100m, 0.00m };   // Free
            yield return new object[] { 49.99m, 25m, 37.4925m };  // Fractional result
            yield return new object[] { 0.00m, 50m, 0.00m };      // Zero price
            yield return new object[] { 199.99m, 15m, 169.9915m }; // Realistic scenario
        }
    }

    [TestMethod]
    [DynamicData(nameof(DiscountTestCases))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpectedPrice(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<object[]> InvalidDiscountTestCases
    {
        get
        {
            yield return new object[] { 100.00m, -1m };    // Below 0
            yield return new object[] { 100.00m, 100.01m }; // Above 100
            yield return new object[] { 50.00m, -50m };    // Large negative
            yield return new object[] { 50.00m, 200m };    // Way above 100
        }
    }

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountTestCases))]
    public void ApplyDiscount_InvalidDiscountPercent_Throws(
        decimal price, decimal discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));
    }

    #endregion

    #region DynamicData with method source

    public static IEnumerable<object[]> GetCalculateTotalEdgeCases()
    {
        // Large quantity
        yield return new object[] { 0.01m, 10000, 0.05m, 105.00m };
        // High-precision unit price
        yield return new object[] { 33.33m, 3, 0.10m, 109.989m };
        // Boundary tax rates
        yield return new object[] { 50.00m, 2, 0.0m, 100.00m };
        yield return new object[] { 50.00m, 2, 1.0m, 200.00m };
    }

    [TestMethod]
    [DynamicData(nameof(GetCalculateTotalEdgeCases), DynamicDataSourceType.Method)]
    public void CalculateTotal_EdgeCases_ReturnsExpectedTotal(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    #endregion
}

